package com.pedrodalben.bigbangeventos.trigger;
import com.pedrodalben.bigbangeventos.api.OperationResult; import com.pedrodalben.bigbangeventos.participant.*; import com.pedrodalben.bigbangeventos.session.SessionState; import java.time.*; import java.util.*;
public final class TriggerService {
    private final Clock clock; private final ParticipantCompletionService completion; private final Map<String,Integer> uses=new HashMap<>(); private final Map<String,Instant> lastUse=new HashMap<>(); public TriggerService(Clock clock,ParticipantCompletionService completion){this.clock=clock;this.completion=completion;}
    public synchronized OperationResult execute(EventTrigger t,TriggerExecutionContext c){if(!t.enabled())return OperationResult.fail("trigger_disabled","Gatilho desabilitado");String key=c.session().id()+":"+t.id();if(t.maxUses()>0&&uses.getOrDefault(key,0)>=t.maxUses())return OperationResult.fail("max_uses","Limite de usos atingido");Instant previous=lastUse.get(key);if(previous!=null&&previous.plus(t.cooldown()).isAfter(clock.instant()))return OperationResult.fail("cooldown","Gatilho em cooldown");for(ConditionType condition:t.conditions()){OperationResult r=condition(condition,c);if(!r.success())return r;}for(TriggerAction action:t.actions()){OperationResult r=action(action,c);if(!r.success())return r;}uses.merge(key,1,Integer::sum);lastUse.put(key,clock.instant());return OperationResult.ok("Gatilho executado");}
    private OperationResult condition(ConditionType x,TriggerExecutionContext c){var p=c.session().participant(c.playerId()).orElse(null);return switch(x){case PLAYER_IS_PARTICIPANT->p==null?OperationResult.fail("condition_failed","Jogador não participa"):OperationResult.ok("ok");case EVENT_IS_RUNNING->c.session().state()!=SessionState.RUNNING?OperationResult.fail("condition_failed","Evento não está em execução"):OperationResult.ok("ok");case PLAYER_NOT_FINISHED->p==null||p.state()==ParticipantState.FINISHED?OperationResult.fail("condition_failed","Jogador já concluiu"):OperationResult.ok("ok");case PLAYER_HAS_PERMISSION->c.permissions().has(c.playerId(),"bigbangeventos.player.trigger")?OperationResult.ok("ok"):OperationResult.fail("condition_failed","Sem permissão");default->OperationResult.ok("Condição preparada, sem restrição nesta versão");};}
    private OperationResult action(TriggerAction a,TriggerExecutionContext c){var p=c.session().participant(c.playerId()).orElse(null);return switch(a.type()){case SEND_MESSAGE->{c.effects().message(c.playerId(),a.arguments().getOrDefault("message",""));yield OperationResult.ok("Mensagem enviada");}case EXECUTE_COMMAND->{c.effects().executeConsole(a.arguments().getOrDefault("command","").replace("{player}",c.playerName()));yield OperationResult.ok("Comando executado");}case ADD_POINTS->{if(p==null)yield OperationResult.fail("not_participant","Jogador não participa");try{p.score(Integer.parseInt(a.arguments().getOrDefault("amount","0")));yield OperationResult.ok("Pontos adicionados");}catch(NumberFormatException e){yield OperationResult.fail("invalid_action","Quantidade de pontos inválida");}}case PLAYER_COMPLETE->completion.complete(c.session(),c.playerId(),CompletionMode.MANUAL_FINISH);case EVENT_FINISH->OperationResult.ok("Encerramento solicitado");case ENABLE_TRIGGER,DISABLE_TRIGGER,TELEPORT->OperationResult.ok("Ação delegada à plataforma");default->OperationResult.fail("not_implemented","Ação ainda não implementada: "+a.type());};}
}
